INSERT INTO posts (id, title, slug, excerpt, cover_image, content_markdown, content_html, content_text, status, source, featured, pinned, comments_enabled, seo_title, seo_description, canonical_url, robots, structured_data, i18n, published_at, created_at, updated_at, author_id, series_id)
VALUES ('post_ai_setup_tutorial_20260605', '用 AI 搭一个自己的个人博客，新手版完整流程', 'ai-setup-personal-blog-tutorial', '从准备 Cloudflare 账号、安装 Codex Cloudflare 插件、clone 模板仓库，到让 AI 自动创建资源和部署博客，这是一份新手友好的完整流程。', '', '这篇教程的目标很简单。

让你用 AI 搭一个自己的个人博客。

你不需要先学完整的前端、后端、数据库、部署。你要做的是准备账号和工具，然后把一段清晰的任务交给 AI。

## 你需要准备什么

准备 3 个东西。

1. 一个 Cloudflare 账号。
2. 一个能执行代码任务的 AI 环境，比如 Codex。
3. `01mvp/blog-starter` 这个仓库。

仓库地址：

```txt
https://github.com/01mvp/blog-starter
```

你可以 fork，也可以 clone，也可以直接下载。推荐 fork 或 clone，这样后面更容易保存自己的改动。

如果你还没有域名，也可以先不用买。Cloudflare Workers 会给你一个 `*.workers.dev` 测试地址。

如果你的读者主要在中国大陆，正式公开时建议准备自己的域名。`*.workers.dev` 在中国大陆很多网络环境里打不开或不稳定。长期稳定、大量公开访问时，还要考虑备案和接入要求。

## 第 1 步，在 Codex 里安装 Cloudflare 插件

在 Codex 里找到插件或连接器入口，安装 Cloudflare。

这一步的作用，是让 AI 能调用 Cloudflare 相关能力。

安装之后，AI 才能帮你创建 D1 数据库、KV 命名空间、R2 存储桶、部署 Worker、绑定域名、检查部署结果。

你可能需要自己登录 Cloudflare，选择账号，确认授权。

这些浏览器登录环节需要你处理，AI 不能替你完成。

## 第 2 步，选择 Skill 或复制 Prompt

推荐安装 01mvp-blog Skill。

Skill 适合长期使用。以后初始化流程有更新，Skill 也能继续更新。

如果你只是想马上试一下，也可以打开文档，复制 AI setup Prompt 给 Codex。

中文文档：

```txt
https://blog.01mvp.com/zh/docs/ai-setup
```

英文文档：

```txt
https://blog.01mvp.com/docs/ai-setup
```

两种方式都可以。

Skill 更适合长期维护，复制 Prompt 更适合快速体验。

## 第 3 步，把任务交给 AI

如果你已经安装 Skill，可以这样对 Codex 说：

```txt
使用 01mvp-blog Skill，帮我基于 https://github.com/01mvp/blog-starter 创建并部署一个个人博客。

我希望 AI 尽量自动完成本地初始化、依赖安装、Cloudflare D1/KV/R2/Worker/DNS 配置、部署、验证和交付报告。

只有 Cloudflare 登录、账号注册、账号选择、域名购买、nameserver 切换、付款方式确认、OAuth 应用创建、邮件验证、API Token 创建这些无法自动完成的环节，才让我手动处理。
```

如果你不想安装 Skill，就复制 AI setup 文档里的完整 Prompt。

## 第 4 步，AI 会向你确认信息

AI 通常会问你这些内容：

1. 博客名称。
2. 作者名称。
3. 主要语言。
4. 是否绑定自定义域名。
5. 是否启用评论。
6. 是否启用 GitHub 或 Google 登录。
7. 是否启用邮件功能。
8. 是否开通 R2。

你可以先选最简单的版本。

博客名称、作者、语言先填好。评论可以打开。自定义域名如果暂时没有，就先跳过。R2 和邮件都可以后面补。

## 第 5 步，AI 会做哪些事

正常情况下，AI 会完成这些工作：

1. clone 或检查你的仓库。
2. 安装 pnpm 依赖。
3. 生成必要的本地配置。
4. 创建 Cloudflare D1 数据库。
5. 创建 KV 命名空间。
6. 按需创建 R2 存储桶。
7. 写入 Worker 配置。
8. 执行数据库迁移。
9. 部署到 Cloudflare Workers。
10. 验证首页、文章页、后台入口、RSS 和站点地图。

你看到 AI 要修改文件时，可以让它列出改动文件。你看到 AI 要执行部署时，可以让它给出部署后的 URL。

## 第 6 步，哪些地方需要你手动处理

这些环节通常需要你自己操作。

Cloudflare 登录，AI 不能替你输入账号密码。

账号选择，如果你有多个 Cloudflare 账号，需要你确认部署到哪一个。

域名购买和 nameserver 切换，需要你在域名服务商或 Cloudflare 控制台处理。

付款方式确认，R2 通常需要绑定付款方式才能开通。R2 有免费额度，但账号层面的付款方式需要你自己确认。

GitHub 和 Google OAuth，需要你自己创建应用，复制 Client ID 和 Secret。

邮件发送，目前 Cloudflare Email Sending 需要 Workers Paid。不开启邮件也能先运行博客，只是没有邮件验证码、密码重置邮件、评论回复通知和博客周报。

## 第 7 步，部署完成后检查什么

部署完成后，至少检查这些页面。

1. 首页能打开。
2. 文章列表能打开。
3. 文档页能打开。
4. `/admin` 后台入口能打开。
5. RSS 地址能打开。
6. 站点地图能打开。
7. 如果绑定了域名，自定义域名能打开。

如果你开了评论，发一条测试评论。

如果你开了登录，测试邮箱登录或社交登录。

如果你开了 R2，上传一张图片。

如果你开了邮件，发一次验证码或密码重置邮件。

## 新手建议

第一次搭建时，不要追求一次性配齐所有功能。

我建议按这个顺序来。

第 1 轮，只跑通博客和后台。

第 2 轮，绑定自定义域名。

第 3 轮，迁移文章和图片。

第 4 轮，再开 R2、邮件、OAuth、API Token。

你只要先把网站跑起来，就已经迈过了最难的一步。

后面的配置，可以慢慢补。', '<p>这篇教程的目标很简单。</p><p>让你用 AI 搭一个自己的个人博客。</p><p>你不需要先学完整的前端、后端、数据库、部署。你要做的是准备账号和工具，然后把一段清晰的任务交给 AI。</p><h2>你需要准备什么</h2><p>准备 3 个东西。</p><ol><li>一个 Cloudflare 账号。</li><li>一个能执行代码任务的 AI 环境，比如 Codex。</li><li><code>01mvp/blog-starter</code> 这个仓库。</li></ol><p>仓库地址：</p><pre><code>https://github.com/01mvp/blog-starter</code></pre><p>你可以 fork，也可以 clone，也可以直接下载。推荐 fork 或 clone，这样后面更容易保存自己的改动。</p><p>如果你还没有域名，也可以先不用买。Cloudflare Workers 会给你一个 <code>*.workers.dev</code> 测试地址。</p><p>如果你的读者主要在中国大陆，正式公开时建议准备自己的域名。<code>*.workers.dev</code> 在中国大陆很多网络环境里打不开或不稳定。长期稳定、大量公开访问时，还要考虑备案和接入要求。</p><h2>第 1 步，在 Codex 里安装 Cloudflare 插件</h2><p>在 Codex 里找到插件或连接器入口，安装 Cloudflare。</p><p>这一步的作用，是让 AI 能调用 Cloudflare 相关能力。</p><p>安装之后，AI 才能帮你创建 D1 数据库、KV 命名空间、R2 存储桶、部署 Worker、绑定域名、检查部署结果。</p><p>你可能需要自己登录 Cloudflare，选择账号，确认授权。</p><p>这些浏览器登录环节需要你处理，AI 不能替你完成。</p><h2>第 2 步，选择 Skill 或复制 Prompt</h2><p>推荐安装 01mvp-blog Skill。</p><p>Skill 适合长期使用。以后初始化流程有更新，Skill 也能继续更新。</p><p>如果你只是想马上试一下，也可以打开文档，复制 AI setup Prompt 给 Codex。</p><p>中文文档：</p><pre><code>https://blog.01mvp.com/zh/docs/ai-setup</code></pre><p>英文文档：</p><pre><code>https://blog.01mvp.com/docs/ai-setup</code></pre><p>两种方式都可以。</p><p>Skill 更适合长期维护，复制 Prompt 更适合快速体验。</p><h2>第 3 步，把任务交给 AI</h2><p>如果你已经安装 Skill，可以这样对 Codex 说：</p><pre><code>使用 01mvp-blog Skill，帮我基于 https://github.com/01mvp/blog-starter 创建并部署一个个人博客。

我希望 AI 尽量自动完成本地初始化、依赖安装、Cloudflare D1/KV/R2/Worker/DNS 配置、部署、验证和交付报告。

只有 Cloudflare 登录、账号注册、账号选择、域名购买、nameserver 切换、付款方式确认、OAuth 应用创建、邮件验证、API Token 创建这些无法自动完成的环节，才让我手动处理。</code></pre><p>如果你不想安装 Skill，就复制 AI setup 文档里的完整 Prompt。</p><h2>第 4 步，AI 会向你确认信息</h2><p>AI 通常会问你这些内容：</p><ol><li>博客名称。</li><li>作者名称。</li><li>主要语言。</li><li>是否绑定自定义域名。</li><li>是否启用评论。</li><li>是否启用 GitHub 或 Google 登录。</li><li>是否启用邮件功能。</li><li>是否开通 R2。</li></ol><p>你可以先选最简单的版本。</p><p>博客名称、作者、语言先填好。评论可以打开。自定义域名如果暂时没有，就先跳过。R2 和邮件都可以后面补。</p><h2>第 5 步，AI 会做哪些事</h2><p>正常情况下，AI 会完成这些工作：</p><ol><li>clone 或检查你的仓库。</li><li>安装 pnpm 依赖。</li><li>生成必要的本地配置。</li><li>创建 Cloudflare D1 数据库。</li><li>创建 KV 命名空间。</li><li>按需创建 R2 存储桶。</li><li>写入 Worker 配置。</li><li>执行数据库迁移。</li><li>部署到 Cloudflare Workers。</li><li>验证首页、文章页、后台入口、RSS 和站点地图。</li></ol><p>你看到 AI 要修改文件时，可以让它列出改动文件。你看到 AI 要执行部署时，可以让它给出部署后的 URL。</p><h2>第 6 步，哪些地方需要你手动处理</h2><p>这些环节通常需要你自己操作。</p><p>Cloudflare 登录，AI 不能替你输入账号密码。</p><p>账号选择，如果你有多个 Cloudflare 账号，需要你确认部署到哪一个。</p><p>域名购买和 nameserver 切换，需要你在域名服务商或 Cloudflare 控制台处理。</p><p>付款方式确认，R2 通常需要绑定付款方式才能开通。R2 有免费额度，但账号层面的付款方式需要你自己确认。</p><p>GitHub 和 Google OAuth，需要你自己创建应用，复制 Client ID 和 Secret。</p><p>邮件发送，目前 Cloudflare Email Sending 需要 Workers Paid。不开启邮件也能先运行博客，只是没有邮件验证码、密码重置邮件、评论回复通知和博客周报。</p><h2>第 7 步，部署完成后检查什么</h2><p>部署完成后，至少检查这些页面。</p><ol><li>首页能打开。</li><li>文章列表能打开。</li><li>文档页能打开。</li><li><code>/admin</code> 后台入口能打开。</li><li>RSS 地址能打开。</li><li>站点地图能打开。</li><li>如果绑定了域名，自定义域名能打开。</li></ol><p>如果你开了评论，发一条测试评论。</p><p>如果你开了登录，测试邮箱登录或社交登录。</p><p>如果你开了 R2，上传一张图片。</p><p>如果你开了邮件，发一次验证码或密码重置邮件。</p><h2>新手建议</h2><p>第一次搭建时，不要追求一次性配齐所有功能。</p><p>我建议按这个顺序来。</p><p>第 1 轮，只跑通博客和后台。</p><p>第 2 轮，绑定自定义域名。</p><p>第 3 轮，迁移文章和图片。</p><p>第 4 轮，再开 R2、邮件、OAuth、API Token。</p><p>你只要先把网站跑起来，就已经迈过了最难的一步。</p><p>后面的配置，可以慢慢补。</p>', '这篇教程的目标很简单。 让你用 AI 搭一个自己的个人博客。 你不需要先学完整的前端、后端、数据库、部署。你要做的是准备账号和工具，然后把一段清晰的任务交给 AI。 你需要准备什么 准备 3 个东西。 1. 一个 Cloudflare 账号。 2. 一个能执行代码任务的 AI 环境，比如 Codex。 3. 01mvp/blog starter 这个仓库。 仓库地址： 你可以 fork，也可以 clone，也可以直接下载。推荐 fork 或 clone，这样后面更容易保存自己的改动。 如果你还没有域名，也可以先不用买。Cloudflare Workers 会给你一个 .workers.dev 测试地址。 如果你的读者主要在中国大陆，正式公开时建议准备自己的域名。 .workers.dev 在中国大陆很多网络环境里打不开或不稳定。长期稳定、大量公开访问时，还要考虑备案和接入要求。 第 1 步，在 Codex 里安装 Cloudflare 插件 在 Codex 里找到插件或连接器入口，安装 Cloudflare。 这一步的作用，是让 AI 能调用 Cloudflare 相关能力。 安装之后，AI 才能帮你创建 D1 数据库、KV 命名空间、R2 存储桶、部署 Worker、绑定域名、检查部署结果。 你可能需要自己登录 Cloudflare，选择账号，确认授权。 这些浏览器登录环节需要你处理，AI 不能替你完成。 第 2 步，选择 Skill 或复制 Prompt 推荐安装 01mvp blog Skill。 Skill 适合长期使用。以后初始化流程有更新，Skill 也能继续更新。 如果你只是想马上试一下，也可以打开文档，复制 AI setup Prompt 给 Codex。 中文文档： 英文文档： 两种方式都可以。 Skill 更适合长期维护，复制 Prompt 更适合快速体验。 第 3 步，把任务交给 AI 如果你已经安装 Skill，可以这样对 Codex 说： 如果你不想安装 Skill，就复制 AI setup 文档里的完整 Prompt。 第 4 步，AI 会向你确认信息 AI 通常会问你这些内容： 1. 博客名称。 2. 作者名称。 3. 主要语言。 4. 是否绑定自定义域名。 5. 是否启用评论。 6. 是否启用 GitHub 或 Google 登录。 7. 是否启用邮件功能。 8. 是否开通 R2。 你可以先选最简单的版本。 博客名称、作者、语言先填好。评论可以打开。自定义域名如果暂时没有，就先跳过。R2 和邮件都可以后面补。 第 5 步，AI 会做哪些事 正常情况下，AI 会完成这些工作： 1. clone 或检查你的仓库。 2. 安装 pnpm 依赖。 3. 生成必要的本地配置。 4. 创建 Cloudflare D1 数据库。 5. 创建 KV 命名空间。 6. 按需创建 R2 存储桶。 7. 写入 Worker 配置。 8. 执行数据库迁移。 9. 部署到 Cloudflare Workers。 10. 验证首页、文章页、后台入口、RSS 和站点地图。 你看到 AI 要修改文件时，可以让它列出改动文件。你看到 AI 要执行部署时，可以让它给出部署后的 URL。 第 6 步，哪些地方需要你手动处理 这些环节通常需要你自己操作。 Cloudflare 登录，AI 不能替你输入账号密码。 账号选择，如果你有多个 Cloudflare 账号，需要你确认部署到哪一个。 域名购买和 nameserver 切换，需要你在域名服务商或 Cloudflare 控制台处理。 付款方式确认，R2 通常需要绑定付款方式才能开通。R2 有免费额度，但账号层面的付款方式需要你自己确认。 GitHub 和 Google OAuth，需要你自己创建应用，复制 Client ID 和 Secret。 邮件发送，目前 Cloudflare Email Sending 需要 Workers Paid。不开启邮件也能先运行博客，只是没有邮件验证码、密码重置邮件、评论回复通知和博客周报。 第 7 步，部署完成后检查什么 部署完成后，至少检查这些页面。 1. 首页能打开。 2. 文章列表能打开。 3. 文档页能打开。 4. /admin 后台入口能打开。 5. RSS 地址能打开。 6. 站点地图能打开。 7. 如果绑定了域名，自定义域名能打开。 如果你开了评论，发一条测试评论。 如果你开了登录，测试邮箱登录或社交登录。 如果你开了 R2，上传一张图片。 如果你开了邮件，发一次验证码或密码重置邮件。 新手建议 第一次搭建时，不要追求一次性配齐所有功能。 我建议按这个顺序来。 第 1 轮，只跑通博客和后台。 第 2 轮，绑定自定义域名。 第 3 轮，迁移文章和图片。 第 4 轮，再开 R2、邮件、OAuth、API Token。 你只要先把网站跑起来，就已经迈过了最难的一步。 后面的配置，可以慢慢补。', 'published', 'ai', 0, 0, 1, '用 AI 搭一个自己的个人博客，新手版完整流程', '01mvp-blog-starter 新手搭建教程，包含 Skill 安装、复制 Prompt、Cloudflare 账号、自定义域名、R2、邮件、OAuth 和 API Token 说明。', NULL, 'index,follow', NULL, '{"title":{"zh":"用 AI 搭一个自己的个人博客，新手版完整流程"},"excerpt":{"zh":"从准备 Cloudflare 账号、安装 Codex Cloudflare 插件、clone 模板仓库，到让 AI 自动创建资源和部署博客，这是一份新手友好的完整流程。"},"contentMarkdown":{"zh":"这篇教程的目标很简单。\n\n让你用 AI 搭一个自己的个人博客。\n\n你不需要先学完整的前端、后端、数据库、部署。你要做的是准备账号和工具，然后把一段清晰的任务交给 AI。\n\n## 你需要准备什么\n\n准备 3 个东西。\n\n1. 一个 Cloudflare 账号。\n2. 一个能执行代码任务的 AI 环境，比如 Codex。\n3. `01mvp/blog-starter` 这个仓库。\n\n仓库地址：\n\n```txt\nhttps://github.com/01mvp/blog-starter\n```\n\n你可以 fork，也可以 clone，也可以直接下载。推荐 fork 或 clone，这样后面更容易保存自己的改动。\n\n如果你还没有域名，也可以先不用买。Cloudflare Workers 会给你一个 `*.workers.dev` 测试地址。\n\n如果你的读者主要在中国大陆，正式公开时建议准备自己的域名。`*.workers.dev` 在中国大陆很多网络环境里打不开或不稳定。长期稳定、大量公开访问时，还要考虑备案和接入要求。\n\n## 第 1 步，在 Codex 里安装 Cloudflare 插件\n\n在 Codex 里找到插件或连接器入口，安装 Cloudflare。\n\n这一步的作用，是让 AI 能调用 Cloudflare 相关能力。\n\n安装之后，AI 才能帮你创建 D1 数据库、KV 命名空间、R2 存储桶、部署 Worker、绑定域名、检查部署结果。\n\n你可能需要自己登录 Cloudflare，选择账号，确认授权。\n\n这些浏览器登录环节需要你处理，AI 不能替你完成。\n\n## 第 2 步，选择 Skill 或复制 Prompt\n\n推荐安装 01mvp-blog Skill。\n\nSkill 适合长期使用。以后初始化流程有更新，Skill 也能继续更新。\n\n如果你只是想马上试一下，也可以打开文档，复制 AI setup Prompt 给 Codex。\n\n中文文档：\n\n```txt\nhttps://blog.01mvp.com/zh/docs/ai-setup\n```\n\n英文文档：\n\n```txt\nhttps://blog.01mvp.com/docs/ai-setup\n```\n\n两种方式都可以。\n\nSkill 更适合长期维护，复制 Prompt 更适合快速体验。\n\n## 第 3 步，把任务交给 AI\n\n如果你已经安装 Skill，可以这样对 Codex 说：\n\n```txt\n使用 01mvp-blog Skill，帮我基于 https://github.com/01mvp/blog-starter 创建并部署一个个人博客。\n\n我希望 AI 尽量自动完成本地初始化、依赖安装、Cloudflare D1/KV/R2/Worker/DNS 配置、部署、验证和交付报告。\n\n只有 Cloudflare 登录、账号注册、账号选择、域名购买、nameserver 切换、付款方式确认、OAuth 应用创建、邮件验证、API Token 创建这些无法自动完成的环节，才让我手动处理。\n```\n\n如果你不想安装 Skill，就复制 AI setup 文档里的完整 Prompt。\n\n## 第 4 步，AI 会向你确认信息\n\nAI 通常会问你这些内容：\n\n1. 博客名称。\n2. 作者名称。\n3. 主要语言。\n4. 是否绑定自定义域名。\n5. 是否启用评论。\n6. 是否启用 GitHub 或 Google 登录。\n7. 是否启用邮件功能。\n8. 是否开通 R2。\n\n你可以先选最简单的版本。\n\n博客名称、作者、语言先填好。评论可以打开。自定义域名如果暂时没有，就先跳过。R2 和邮件都可以后面补。\n\n## 第 5 步，AI 会做哪些事\n\n正常情况下，AI 会完成这些工作：\n\n1. clone 或检查你的仓库。\n2. 安装 pnpm 依赖。\n3. 生成必要的本地配置。\n4. 创建 Cloudflare D1 数据库。\n5. 创建 KV 命名空间。\n6. 按需创建 R2 存储桶。\n7. 写入 Worker 配置。\n8. 执行数据库迁移。\n9. 部署到 Cloudflare Workers。\n10. 验证首页、文章页、后台入口、RSS 和站点地图。\n\n你看到 AI 要修改文件时，可以让它列出改动文件。你看到 AI 要执行部署时，可以让它给出部署后的 URL。\n\n## 第 6 步，哪些地方需要你手动处理\n\n这些环节通常需要你自己操作。\n\nCloudflare 登录，AI 不能替你输入账号密码。\n\n账号选择，如果你有多个 Cloudflare 账号，需要你确认部署到哪一个。\n\n域名购买和 nameserver 切换，需要你在域名服务商或 Cloudflare 控制台处理。\n\n付款方式确认，R2 通常需要绑定付款方式才能开通。R2 有免费额度，但账号层面的付款方式需要你自己确认。\n\nGitHub 和 Google OAuth，需要你自己创建应用，复制 Client ID 和 Secret。\n\n邮件发送，目前 Cloudflare Email Sending 需要 Workers Paid。不开启邮件也能先运行博客，只是没有邮件验证码、密码重置邮件、评论回复通知和博客周报。\n\n## 第 7 步，部署完成后检查什么\n\n部署完成后，至少检查这些页面。\n\n1. 首页能打开。\n2. 文章列表能打开。\n3. 文档页能打开。\n4. `/admin` 后台入口能打开。\n5. RSS 地址能打开。\n6. 站点地图能打开。\n7. 如果绑定了域名，自定义域名能打开。\n\n如果你开了评论，发一条测试评论。\n\n如果你开了登录，测试邮箱登录或社交登录。\n\n如果你开了 R2，上传一张图片。\n\n如果你开了邮件，发一次验证码或密码重置邮件。\n\n## 新手建议\n\n第一次搭建时，不要追求一次性配齐所有功能。\n\n我建议按这个顺序来。\n\n第 1 轮，只跑通博客和后台。\n\n第 2 轮，绑定自定义域名。\n\n第 3 轮，迁移文章和图片。\n\n第 4 轮，再开 R2、邮件、OAuth、API Token。\n\n你只要先把网站跑起来，就已经迈过了最难的一步。\n\n后面的配置，可以慢慢补。"},"contentHtml":{"zh":"<p>这篇教程的目标很简单。</p><p>让你用 AI 搭一个自己的个人博客。</p><p>你不需要先学完整的前端、后端、数据库、部署。你要做的是准备账号和工具，然后把一段清晰的任务交给 AI。</p><h2>你需要准备什么</h2><p>准备 3 个东西。</p><ol><li>一个 Cloudflare 账号。</li><li>一个能执行代码任务的 AI 环境，比如 Codex。</li><li><code>01mvp/blog-starter</code> 这个仓库。</li></ol><p>仓库地址：</p><pre><code>https://github.com/01mvp/blog-starter</code></pre><p>你可以 fork，也可以 clone，也可以直接下载。推荐 fork 或 clone，这样后面更容易保存自己的改动。</p><p>如果你还没有域名，也可以先不用买。Cloudflare Workers 会给你一个 <code>*.workers.dev</code> 测试地址。</p><p>如果你的读者主要在中国大陆，正式公开时建议准备自己的域名。<code>*.workers.dev</code> 在中国大陆很多网络环境里打不开或不稳定。长期稳定、大量公开访问时，还要考虑备案和接入要求。</p><h2>第 1 步，在 Codex 里安装 Cloudflare 插件</h2><p>在 Codex 里找到插件或连接器入口，安装 Cloudflare。</p><p>这一步的作用，是让 AI 能调用 Cloudflare 相关能力。</p><p>安装之后，AI 才能帮你创建 D1 数据库、KV 命名空间、R2 存储桶、部署 Worker、绑定域名、检查部署结果。</p><p>你可能需要自己登录 Cloudflare，选择账号，确认授权。</p><p>这些浏览器登录环节需要你处理，AI 不能替你完成。</p><h2>第 2 步，选择 Skill 或复制 Prompt</h2><p>推荐安装 01mvp-blog Skill。</p><p>Skill 适合长期使用。以后初始化流程有更新，Skill 也能继续更新。</p><p>如果你只是想马上试一下，也可以打开文档，复制 AI setup Prompt 给 Codex。</p><p>中文文档：</p><pre><code>https://blog.01mvp.com/zh/docs/ai-setup</code></pre><p>英文文档：</p><pre><code>https://blog.01mvp.com/docs/ai-setup</code></pre><p>两种方式都可以。</p><p>Skill 更适合长期维护，复制 Prompt 更适合快速体验。</p><h2>第 3 步，把任务交给 AI</h2><p>如果你已经安装 Skill，可以这样对 Codex 说：</p><pre><code>使用 01mvp-blog Skill，帮我基于 https://github.com/01mvp/blog-starter 创建并部署一个个人博客。\n\n我希望 AI 尽量自动完成本地初始化、依赖安装、Cloudflare D1/KV/R2/Worker/DNS 配置、部署、验证和交付报告。\n\n只有 Cloudflare 登录、账号注册、账号选择、域名购买、nameserver 切换、付款方式确认、OAuth 应用创建、邮件验证、API Token 创建这些无法自动完成的环节，才让我手动处理。</code></pre><p>如果你不想安装 Skill，就复制 AI setup 文档里的完整 Prompt。</p><h2>第 4 步，AI 会向你确认信息</h2><p>AI 通常会问你这些内容：</p><ol><li>博客名称。</li><li>作者名称。</li><li>主要语言。</li><li>是否绑定自定义域名。</li><li>是否启用评论。</li><li>是否启用 GitHub 或 Google 登录。</li><li>是否启用邮件功能。</li><li>是否开通 R2。</li></ol><p>你可以先选最简单的版本。</p><p>博客名称、作者、语言先填好。评论可以打开。自定义域名如果暂时没有，就先跳过。R2 和邮件都可以后面补。</p><h2>第 5 步，AI 会做哪些事</h2><p>正常情况下，AI 会完成这些工作：</p><ol><li>clone 或检查你的仓库。</li><li>安装 pnpm 依赖。</li><li>生成必要的本地配置。</li><li>创建 Cloudflare D1 数据库。</li><li>创建 KV 命名空间。</li><li>按需创建 R2 存储桶。</li><li>写入 Worker 配置。</li><li>执行数据库迁移。</li><li>部署到 Cloudflare Workers。</li><li>验证首页、文章页、后台入口、RSS 和站点地图。</li></ol><p>你看到 AI 要修改文件时，可以让它列出改动文件。你看到 AI 要执行部署时，可以让它给出部署后的 URL。</p><h2>第 6 步，哪些地方需要你手动处理</h2><p>这些环节通常需要你自己操作。</p><p>Cloudflare 登录，AI 不能替你输入账号密码。</p><p>账号选择，如果你有多个 Cloudflare 账号，需要你确认部署到哪一个。</p><p>域名购买和 nameserver 切换，需要你在域名服务商或 Cloudflare 控制台处理。</p><p>付款方式确认，R2 通常需要绑定付款方式才能开通。R2 有免费额度，但账号层面的付款方式需要你自己确认。</p><p>GitHub 和 Google OAuth，需要你自己创建应用，复制 Client ID 和 Secret。</p><p>邮件发送，目前 Cloudflare Email Sending 需要 Workers Paid。不开启邮件也能先运行博客，只是没有邮件验证码、密码重置邮件、评论回复通知和博客周报。</p><h2>第 7 步，部署完成后检查什么</h2><p>部署完成后，至少检查这些页面。</p><ol><li>首页能打开。</li><li>文章列表能打开。</li><li>文档页能打开。</li><li><code>/admin</code> 后台入口能打开。</li><li>RSS 地址能打开。</li><li>站点地图能打开。</li><li>如果绑定了域名，自定义域名能打开。</li></ol><p>如果你开了评论，发一条测试评论。</p><p>如果你开了登录，测试邮箱登录或社交登录。</p><p>如果你开了 R2，上传一张图片。</p><p>如果你开了邮件，发一次验证码或密码重置邮件。</p><h2>新手建议</h2><p>第一次搭建时，不要追求一次性配齐所有功能。</p><p>我建议按这个顺序来。</p><p>第 1 轮，只跑通博客和后台。</p><p>第 2 轮，绑定自定义域名。</p><p>第 3 轮，迁移文章和图片。</p><p>第 4 轮，再开 R2、邮件、OAuth、API Token。</p><p>你只要先把网站跑起来，就已经迈过了最难的一步。</p><p>后面的配置，可以慢慢补。</p>"},"contentText":{"zh":"这篇教程的目标很简单。 让你用 AI 搭一个自己的个人博客。 你不需要先学完整的前端、后端、数据库、部署。你要做的是准备账号和工具，然后把一段清晰的任务交给 AI。 你需要准备什么 准备 3 个东西。 1. 一个 Cloudflare 账号。 2. 一个能执行代码任务的 AI 环境，比如 Codex。 3. 01mvp/blog starter 这个仓库。 仓库地址： 你可以 fork，也可以 clone，也可以直接下载。推荐 fork 或 clone，这样后面更容易保存自己的改动。 如果你还没有域名，也可以先不用买。Cloudflare Workers 会给你一个 .workers.dev 测试地址。 如果你的读者主要在中国大陆，正式公开时建议准备自己的域名。 .workers.dev 在中国大陆很多网络环境里打不开或不稳定。长期稳定、大量公开访问时，还要考虑备案和接入要求。 第 1 步，在 Codex 里安装 Cloudflare 插件 在 Codex 里找到插件或连接器入口，安装 Cloudflare。 这一步的作用，是让 AI 能调用 Cloudflare 相关能力。 安装之后，AI 才能帮你创建 D1 数据库、KV 命名空间、R2 存储桶、部署 Worker、绑定域名、检查部署结果。 你可能需要自己登录 Cloudflare，选择账号，确认授权。 这些浏览器登录环节需要你处理，AI 不能替你完成。 第 2 步，选择 Skill 或复制 Prompt 推荐安装 01mvp blog Skill。 Skill 适合长期使用。以后初始化流程有更新，Skill 也能继续更新。 如果你只是想马上试一下，也可以打开文档，复制 AI setup Prompt 给 Codex。 中文文档： 英文文档： 两种方式都可以。 Skill 更适合长期维护，复制 Prompt 更适合快速体验。 第 3 步，把任务交给 AI 如果你已经安装 Skill，可以这样对 Codex 说： 如果你不想安装 Skill，就复制 AI setup 文档里的完整 Prompt。 第 4 步，AI 会向你确认信息 AI 通常会问你这些内容： 1. 博客名称。 2. 作者名称。 3. 主要语言。 4. 是否绑定自定义域名。 5. 是否启用评论。 6. 是否启用 GitHub 或 Google 登录。 7. 是否启用邮件功能。 8. 是否开通 R2。 你可以先选最简单的版本。 博客名称、作者、语言先填好。评论可以打开。自定义域名如果暂时没有，就先跳过。R2 和邮件都可以后面补。 第 5 步，AI 会做哪些事 正常情况下，AI 会完成这些工作： 1. clone 或检查你的仓库。 2. 安装 pnpm 依赖。 3. 生成必要的本地配置。 4. 创建 Cloudflare D1 数据库。 5. 创建 KV 命名空间。 6. 按需创建 R2 存储桶。 7. 写入 Worker 配置。 8. 执行数据库迁移。 9. 部署到 Cloudflare Workers。 10. 验证首页、文章页、后台入口、RSS 和站点地图。 你看到 AI 要修改文件时，可以让它列出改动文件。你看到 AI 要执行部署时，可以让它给出部署后的 URL。 第 6 步，哪些地方需要你手动处理 这些环节通常需要你自己操作。 Cloudflare 登录，AI 不能替你输入账号密码。 账号选择，如果你有多个 Cloudflare 账号，需要你确认部署到哪一个。 域名购买和 nameserver 切换，需要你在域名服务商或 Cloudflare 控制台处理。 付款方式确认，R2 通常需要绑定付款方式才能开通。R2 有免费额度，但账号层面的付款方式需要你自己确认。 GitHub 和 Google OAuth，需要你自己创建应用，复制 Client ID 和 Secret。 邮件发送，目前 Cloudflare Email Sending 需要 Workers Paid。不开启邮件也能先运行博客，只是没有邮件验证码、密码重置邮件、评论回复通知和博客周报。 第 7 步，部署完成后检查什么 部署完成后，至少检查这些页面。 1. 首页能打开。 2. 文章列表能打开。 3. 文档页能打开。 4. /admin 后台入口能打开。 5. RSS 地址能打开。 6. 站点地图能打开。 7. 如果绑定了域名，自定义域名能打开。 如果你开了评论，发一条测试评论。 如果你开了登录，测试邮箱登录或社交登录。 如果你开了 R2，上传一张图片。 如果你开了邮件，发一次验证码或密码重置邮件。 新手建议 第一次搭建时，不要追求一次性配齐所有功能。 我建议按这个顺序来。 第 1 轮，只跑通博客和后台。 第 2 轮，绑定自定义域名。 第 3 轮，迁移文章和图片。 第 4 轮，再开 R2、邮件、OAuth、API Token。 你只要先把网站跑起来，就已经迈过了最难的一步。 后面的配置，可以慢慢补。"},"seoTitle":{"zh":"用 AI 搭一个自己的个人博客，新手版完整流程"},"seoDescription":{"zh":"01mvp-blog-starter 新手搭建教程，包含 Skill 安装、复制 Prompt、Cloudflare 账号、自定义域名、R2、邮件、OAuth 和 API Token 说明。"}}', '2026-06-05T05:45:00.000Z', '2026-06-05T05:45:00.000Z', '2026-06-05T06:00:00.000Z', NULL, NULL)
ON CONFLICT(slug) DO UPDATE SET
title = excluded.title,
excerpt = excluded.excerpt,
cover_image = excluded.cover_image,
content_markdown = excluded.content_markdown,
content_html = excluded.content_html,
content_text = excluded.content_text,
status = excluded.status,
source = excluded.source,
featured = excluded.featured,
pinned = excluded.pinned,
comments_enabled = excluded.comments_enabled,
seo_title = excluded.seo_title,
seo_description = excluded.seo_description,
robots = excluded.robots,
structured_data = excluded.structured_data,
i18n = excluded.i18n,
published_at = excluded.published_at,
updated_at = excluded.updated_at;
DELETE FROM post_tags WHERE post_id = (SELECT id FROM posts WHERE slug = 'ai-setup-personal-blog-tutorial');
INSERT OR IGNORE INTO post_tags (post_id, tag_id) VALUES ((SELECT id FROM posts WHERE slug = 'ai-setup-personal-blog-tutorial'), (SELECT id FROM tags WHERE slug = '教程'));
INSERT OR IGNORE INTO post_tags (post_id, tag_id) VALUES ((SELECT id FROM posts WHERE slug = 'ai-setup-personal-blog-tutorial'), (SELECT id FROM tags WHERE slug = 'ai-建站'));
INSERT OR IGNORE INTO post_tags (post_id, tag_id) VALUES ((SELECT id FROM posts WHERE slug = 'ai-setup-personal-blog-tutorial'), (SELECT id FROM tags WHERE slug = 'cloudflare'));
INSERT OR IGNORE INTO post_tags (post_id, tag_id) VALUES ((SELECT id FROM posts WHERE slug = 'ai-setup-personal-blog-tutorial'), (SELECT id FROM tags WHERE slug = '01mvp'));

SELECT slug, title, status, published_at FROM posts WHERE slug IN ('why-i-built-an-ai-maintained-personal-blog', 'why-this-blog-uses-cloudflare-stack', 'ai-setup-personal-blog-tutorial') ORDER BY published_at DESC;
